  1	import type { FC, MouseEvent, ReactNode } from 'react';
  2	
  3	import { ExternalLink } from '@components/common/ExternalLink/ExternalLink';
  4	import {
  5	  Breadcrumb,
  6	  BreadcrumbItem,
  7	  Button,
  8	  ButtonVariant,
  9	  DescriptionListDescription,
 10	  DescriptionListGroup,
 11	  DescriptionListTerm,
 12	  DescriptionListTermHelpText,
 13	  DescriptionListTermHelpTextButton,
 14	  Flex,
 15	  FlexItem,
 16	  Icon,
 17	  Popover,
 18	  Truncate,
 19	} from '@patternfly/react-core';
 20	import { HelpIcon, PencilAltIcon as Pencil } from '@patternfly/react-icons';
 21	import { isEmpty } from '@utils/helpers';
 22	
 23	import { ensureArray } from '../../utils/ensureArray';
 24	
 25	/**
 26	 * Component for displaying title with help text in a popover.
 27	 *
 28	 * @component
 29	 */
 30	const DescriptionTitleWithHelp: FC<{
 31	  title: string;
 32	  helpContent: ReactNode;
 33	  showHelpIconNextToTitle: boolean;
 34	  moreInfoLabel?: string;
 35	  moreInfoLink?: string;
 36	  crumbs?: string[];
 37	}> = ({
 38	  crumbs,
 39	  helpContent,
 40	  moreInfoLabel = 'More info:',
 41	  moreInfoLink,
 42	  showHelpIconNextToTitle = false,
 43	  title,
 44	}) => {
 45	  const onClick: (event: MouseEvent<HTMLButtonElement>) => void = (event) => {
 46	    event.preventDefault();
 47	  };
 48	
 49	  return (
 50	    <DescriptionListTermHelpText className="pf-v6-u-align-items-center">
 51	      {showHelpIconNextToTitle ? <div>{title} &nbsp;</div> : null}
 52	      <Popover
 53	        headerContent={<div>{title}</div>}
 54	        bodyContent={
 55	          <Flex direction={{ default: 'column' }}>
 56	            <FlexItem>{helpContent}</FlexItem>
 57	
 58	            {moreInfoLink && (
 59	              <FlexItem>
 60	                {moreInfoLabel}{' '}
 61	                <ExternalLink href={moreInfoLink} isInline hideIcon>
 62	                  <Truncate content={moreInfoLink} />
 63	                </ExternalLink>
 64	              </FlexItem>
 65	            )}
 66	
 67	            {!isEmpty(crumbs) && (
 68	              <FlexItem>
 69	                <Breadcrumb>
 70	                  {crumbs.map((crumb) => (
 71	                    <BreadcrumbItem key={crumb}>{crumb}</BreadcrumbItem>
 72	                  ))}
 73	                </Breadcrumb>
 74	              </FlexItem>
 75	            )}
 76	          </Flex>
 77	        }
 78	      >
 79	        {showHelpIconNextToTitle ? (
 80	          <Button variant={ButtonVariant.plain} className="pf-v6-u-p-0" onClick={onClick} icon={<Icon size="sm"><HelpIcon /></Icon>} />
 81	        ) : (
 82	          <DescriptionListTermHelpTextButton> {title} </DescriptionListTermHelpTextButton>
 83	        )}
 84	      </Popover>
 85	    </DescriptionListTermHelpText>
 86	  );
 87	};
 88	
 89	/**
 90	 * Component for displaying title without a popover.
 91	 *
 92	 * @component
 93	 */
 94	const DescriptionTitle: FC<{ title: string }> = ({ title }) => (
 95	  <DescriptionListTerm> {title} </DescriptionListTerm>
 96	);
 97	
 98	/**
 99	 * Component for displaying an item's title
100	 *
101	 * @component
102	 */
103	export const DisplayTitle: FC<{
104	  title: string;
105	  helpContent?: ReactNode;
106	  showHelpIconNextToTitle?: boolean;
107	  moreInfoLabel?: string;
108	  moreInfoLink?: string;
109	  crumbs?: string[];
110	}> = ({
111	  crumbs,
112	  helpContent,
113	  moreInfoLabel,
114	  moreInfoLink,
115	  showHelpIconNextToTitle = false,
116	  title,
117	}) =>
118	  helpContent ? (
119	    <DescriptionTitleWithHelp
120	      title={title}
121	      helpContent={helpContent}
122	      showHelpIconNextToTitle={showHelpIconNextToTitle}
123	      moreInfoLabel={moreInfoLabel}
124	      moreInfoLink={moreInfoLink}
125	      crumbs={crumbs}
126	    />
127	  ) : (
128	    <DescriptionTitle title={title} />
129	  );
130	
131	/**
132	 * Component for displaying an editable or non editable content field with the following format:
133	 * The content field's element and if editable, next to that appears a press-able inline
134	 * link edit button with the pencil icon, for triggering the onEdit callback.
135	 *
136	 * @component
137	 * @param {ReactNode} content - The field's content element.
138	 * @param {Function} onEdit - Function to be called when the button is clicked.
139	 */
140	
141	const ContentField: FC<{
142	  content: ReactNode;
143	  onEdit: () => void;
144	  canEdit?: boolean;
145	}> = ({ canEdit = true, content, onEdit }) =>
146	  canEdit && onEdit ? (
147	    <DescriptionListDescription>
148	      <Flex alignItems={{ default: 'alignItemsCenter' }}>
149	        <FlexItem spacer={{ default: 'spacerNone' }}>{content}</FlexItem>
150	        <FlexItem spacer={{ default: 'spacerNone' }}>
151	          <Button
152	            variant={ButtonVariant.link}
153	            isInline
154	            onClick={onEdit}
155	            icon={<Pencil />}
156	            iconPosition="right"
157	          />
158	        </FlexItem>
159	      </Flex>
160	    </DescriptionListDescription>
161	  ) : (
162	    <DescriptionListDescription>{content}</DescriptionListDescription>
163	  );
164	
165	/**
166	 * Component for displaying a details item.
167	 * It can optionally include a help text popover, breadcrumbs, and an edit button.
168	 *
169	 * @component
170	 * @param {DetailsItemProps} props - The props of the details item.
171	 */
172	
173	/**
174	 * Type for the props of the DetailsItem component.
175	 *
176	 * @typedef {Object} DetailsItemProps
177	 * @property {string} title - The title of the details item.
178	 * @property {ReactNode} [helpContent] - The content to display in the help popover.
179	 * @property {ReactNode} [showHelpIconNextToTitle] - if true, adding a help icon next to the title for displaying the help popover.
180	 *    If false, show the default Patternfly dashed line under the title.
181	 * @property {string[]} [crumbs] - Breadcrumbs for the details item.
182	 * @property {ReactNode | ReactNode[]} content - Array of content fields to be displayed for the details item.
183	 * @property {Function | Function[]} onEdit - Array of functions per content field to be called when the edit button is clicked or null if the field is non editable.
184	 * @property {boolean} [showEditButton] - If true, show the edit button next to the content field, when missing falling back to onEdit existence.
185	 */
186	type DetailsItemProps = {
187	  title: string;
188	  testId?: string;
189	  helpContent?: ReactNode;
190	  showHelpIconNextToTitle?: boolean;
191	  moreInfoLabel?: string;
192	  moreInfoLink?: string;
193	  crumbs?: string[];
194	  content: ReactNode | ReactNode[];
195	  onEdit?: (() => void) | (() => void)[];
196	  canEdit?: boolean;
197	};
198	
199	export const DetailsItem: FC<DetailsItemProps> = ({
200	  canEdit,
201	  content,
202	  crumbs,
203	  helpContent,
204	  moreInfoLabel,
205	  moreInfoLink,
206	  onEdit,
207	  showHelpIconNextToTitle,
208	  testId,
209	  title,
210	}) => {
211	  const contents = ensureArray(content);
212	  const onEdits = ensureArray(onEdit);
213	
214	  return (
215	    <DescriptionListGroup data-testid={testId}>
216	      <DisplayTitle
217	        title={title}
218	        helpContent={helpContent}
219	        showHelpIconNextToTitle={showHelpIconNextToTitle}
220	        moreInfoLabel={moreInfoLabel}
221	        moreInfoLink={moreInfoLink}
222	        crumbs={crumbs}
223	      />
224	      <DescriptionListDescription>
225	        {contents?.map((value, index) => (
226	          <ContentField
227	            key={`content-field-${index}`}
228	            content={value as ReactNode}
229	            onEdit={onEdits?.[index] as () => void}
230	            canEdit={canEdit}
231	          />
232	        ))}
233	      </DescriptionListDescription>
234	    </DescriptionListGroup>
235	  );
236	};

